const item = $input.first().json;
const html = item.html || item.data || '';
const url = $('Form Trigger').first().json['URL'] || 'unknown';

const cleaned = html
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<script(?![\s\S]*?type=["']application\/ld\+json["'])[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '');

// HEAD section (increased to 6000 chars to avoid truncating heavy schema)
const headMatch = cleaned.match(/<head[\s\S]*?<\/head>/i);
const head = headMatch ? headMatch[0].substring(0, 6000) : '(no <head> found)';

// Heading hierarchy
const headings = [];
const hMatches = cleaned.matchAll(/<h([1-6])[^>]*>([\s\S]*?)<\/h[1-6]>/gi);
for (const m of hMatches) {
  headings.push('H' + m[1] + ': ' + m[2].replace(/<[^>]+>/g, '').trim());
}

// Image alt attributes
const alts = [];
const imgMatches = cleaned.matchAll(/<img[^>]+>/gi);
for (const m of imgMatches) {
  const alt = m[0].match(/alt=["']([^"']*)["']/i);
  alts.push(alt ? (alt[1] || '(empty alt)') : '(missing alt)');
}

// Internal and external links
const links = [];
const linkMatches = cleaned.matchAll(/<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi);
for (const m of linkMatches) {
  links.push({ href: m[1], text: m[2].replace(/<[^>]+>/g, '').trim().substring(0, 80) });
}

// Clean body text
const bodyText = cleaned
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 8000);

const wordCount = bodyText.split(/\s+/).filter(function(w) { return w.length > 1; }).length;

return [{ json: {
  url: url,
  head: head,
  text: bodyText,
  wordCount: wordCount,
  headings: headings.slice(0, 60).join('\n'),
  images: alts.slice(0, 40).join(' | '),
  links: links.slice(0, 50)
} }];
